// build.rs — runs at `cargo build` time.
//
// Two responsibilities, in order:
//   1. Compile the 10 .proto files under proto/ into Rust structs via
//      prost-build. Output goes to OUT_DIR/<proto_package>.rs; src/proto.rs
//      then `include!`s these. This replaces the Go libgm's autogenerated
//      *.pb.go layer (~15.6k LOC) with equivalent Rust — re-generated on
//      every build, never checked in.
//
//   2. Generate the UniFFI scaffolding from src/lib.udl. UniFFI produces
//      the JNI exports + the Kotlin bindings file (textrcs_libgm.kt) that
//      lives in build/uniffi/<arch>/ after the gradle plugin runs against
//      our .so.
//
// Both steps re-run when their inputs change (cargo invalidates build.rs
// outputs when the listed files change via println!("cargo:rerun-if-changed=...")).

use std::path::PathBuf;

fn main() {
    let proto_dir = PathBuf::from("proto");
    let proto_files = [
        "authentication.proto",
        "client.proto",
        "config.proto",
        "conversations.proto",
        "events.proto",
        "rpc.proto",
        "settings.proto",
        "ukey.proto",
        "util.proto",
    ];

    // Tell cargo to re-run this build script whenever a .proto file changes.
    println!("cargo:rerun-if-changed=proto/");
    for f in &proto_files {
        println!("cargo:rerun-if-changed=proto/{}", f);
    }
    println!("cargo:rerun-if-changed=build.rs");
    // No UDL — we use uniffi proc-macros (#[uniffi::export], #[derive(uniffi::Object)])
    // in the source. UDL was tried initially but had a syntax error and the
    // proc-macro path is the modern UniFFI 0.28+ idiom anyway.

    // --- prost-reflect-build: .proto → generated Rust + ReflectMessage impls ---
    // We use prost-reflect-build instead of plain prost-build because the
    // generated types need to implement prost_reflect::ReflectMessage so
    // src/pblite.rs can introspect them at runtime (Rust equivalent of
    // Go's protoreflect API). prost-reflect-build wraps prost-build and
    // adds the trait impls automatically (descriptor pool loaded once,
    // each generated struct knows its FQN).
    //
    // Bytes-field note: default codegen produces prost::bytes::Bytes for
    // proto `bytes`. We accept the default — Vec<u8> conversion happens
    // at the FFI boundary in src/client.rs. (Previous attempt to add
    // type-wide serde derives via prost_cfg.type_attribute(".", ...) was
    // dropped because prost::bytes::Bytes has no serde::Deserialize impl.)

    let proto_paths: Vec<PathBuf> = proto_files
        .iter()
        .map(|f| proto_dir.join(f))
        .collect();

    let descriptor_path = std::path::PathBuf::from(std::env::var("OUT_DIR").unwrap())
        .join("file_descriptor_set.bin");

    prost_reflect_build::Builder::new()
        .file_descriptor_set_path(&descriptor_path)
        // Tell the generated ReflectMessage impls to load their descriptor
        // pool from the binary file we just emitted (OUT_DIR/file_descriptor_set.bin).
        // prost-reflect-build splices this expression into each generated
        // impl, where it's lazily initialized once and shared across all
        // proto types.
        .file_descriptor_set_bytes(
            "crate::pblite::FILE_DESCRIPTOR_SET_BYTES",
        )
        .compile_protos(&proto_paths, &[proto_dir])
        .expect("prost-reflect-build: failed to compile .proto files");

    // --- UniFFI: proc-macro approach ---
    // No generate_scaffolding call — uniffi::setup_scaffolding!() in
    // src/lib.rs handles registration via macros driven by the
    // #[uniffi::export] / #[derive(uniffi::Object)] annotations on
    // the types in src/{client,pair,error}.rs.
}
